package com.ll;

import java.io.ByteArrayInputStream;
import java.io.ByteArrayOutputStream;
import java.io.InputStream;
import java.io.PrintStream;
import java.nio.charset.StandardCharsets;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

@DisplayName("App 테스트")
class AppTest {

    private App app;

    @BeforeEach
    void setUp() {
        app = new App();
    }

    // 콘솔 입력(lines)을 주입해 App을 실행하고 출력 문자열을 반환하는 테스트 헬퍼
    private String runAppWithInput(String... lines) {
        InputStream originalIn = System.in;
        PrintStream originalOut = System.out;
        ByteArrayOutputStream outputBuffer = new ByteArrayOutputStream();

        try {
            String input = String.join(System.lineSeparator(), lines) + System.lineSeparator();
            System.setIn(new ByteArrayInputStream(input.getBytes(StandardCharsets.UTF_8)));
            System.setOut(new PrintStream(outputBuffer, true, StandardCharsets.UTF_8));

            App consoleApp = new App();
            consoleApp.run();

            return outputBuffer.toString(StandardCharsets.UTF_8);
        } finally {
            System.setIn(originalIn);
            System.setOut(originalOut);
        }
    }

    // 중복 코드 리펙토링
    private String[] writeCommand(String title, String content) {
        return new String[]{"write", title, content};
    }

    private String runWithTwoArticlesThen(String... tailCommands) {
        String[] first = writeCommand("첫번째 제목", "첫번째 내용");
        String[] second = writeCommand("두번째 제목", "두번째 내용");
        String[] all = new String[first.length + second.length + tailCommands.length + 1];

        int idx = 0;
        for (String cmd : first) all[idx++] = cmd;
        for (String cmd : second) all[idx++] = cmd;
        for (String cmd : tailCommands) all[idx++] = cmd;
        all[idx] = "exit";

        return runAppWithInput(all);
    }

    // output에 expectedTexts가 모두 포함되는지 한 번에 검증하는 헬퍼
    private void assertContainsAll(String output, String... expectedTexts) {
        for (String expected : expectedTexts) {
            assertTrue(output.contains(expected));
        }
    }

    // 마지막으로 출력된 list 표 블록(헤더부터)을 추출하는 헬퍼
    private String extractLastListBlock(String output) {
        String header = "번호 | 제목 | 등록일 | 조회수";
        int idx = output.lastIndexOf(header);
        if (idx < 0) return "";
        return output.substring(idx);
    }

    // --------------------------------------
    // 테스트 케이스
    // --------------------------------------
    @Nested
    @DisplayName("게시글 목록 출력(listArticles) 테스트")
    class ListArticlesTest {

        @Test
        @DisplayName("게시글이 없을 때 빈 목록이 출력되는지 확인")
        void showsEmptyMessageWhenNoArticles() {
            String output = runAppWithInput("list", "exit");

            assertTrue(output.contains("번호 | 제목 | 등록일 | 조회수"));
            assertTrue(output.contains("(게시글 없음)"));
        }

        @Test
        @DisplayName("여러 게시글이 등록되었을 때, 목록이 올바르게 출력되는지 확인")
        void showsAllArticlesInList() {
            String output = runWithTwoArticlesThen("list");

            assertContainsAll(output, "1    | 첫번째 제목", "2    | 두번째 제목");
        }

        @Test
        @DisplayName("최신 게시글이 목록의 상단에 위치하는지 확인")
        void latestArticleAppearsFirst() {
            String output = runWithTwoArticlesThen("list");

            int secondIndex = output.indexOf("2    | 두번째 제목");
            int firstIndex = output.indexOf("1    | 첫번째 제목");

            assertTrue(secondIndex >= 0);
            assertTrue(firstIndex >= 0);
            assertTrue(secondIndex < firstIndex);
        }

        @Test
        @DisplayName("list에서 신규 게시글 조회수가 0으로 표시되는지 확인")
        void showsZeroViewCountInListForNewArticle() {
            String output = runAppWithInput(
                    "write", "조회수 초기 테스트", "내용",
                    "list",
                    "exit"
            );

            String listBlock = extractLastListBlock(output);
            assertContainsAll(listBlock, "번호 | 제목 | 등록일 | 조회수", "1    | 조회수 초기 테스트", "| 0");
        }

        @Test
        @DisplayName("detail 이후 list에서 조회수가 증가한 값으로 표시되는지 확인")
        void reflectsIncreasedViewCountInListAfterDetail() {
            String output = runAppWithInput(
                    "write", "조회수 반영 테스트", "내용",
                    "detail 1",
                    "list",
                    "exit"
            );

            String listBlock = extractLastListBlock(output);
            assertContainsAll(listBlock, "1    | 조회수 반영 테스트", "| 1");
        }

        @Test
        @DisplayName("여러 게시글 중 상세 조회한 게시글만 조회수가 증가하는지 확인")
        void increasesViewCountOnlyForViewedArticleInList() {
            String output = runAppWithInput(
                    "write", "첫번째 글", "내용1",
                    "write", "두번째 글", "내용2",
                    "detail 1",
                    "list",
                    "exit"
            );

            String listBlock = extractLastListBlock(output);
            assertContainsAll(listBlock, "2    | 두번째 글", "| 0", "1    | 첫번째 글", "| 1");
        }
    }

    @Nested
    @DisplayName("게시글 상세보기(showDetail) 테스트 케이스")
    class ShowDetailTest {

        @Test
        @DisplayName("존재하지 않는 ID로 상세보기를 요청할 때 예외가 발생하는지 확인")
        void showsErrorMessageWhenIdDoesNotExist() {
            String output = runAppWithInput("detail 999", "exit");

            assertTrue(output.contains("해당 아이디는 존재하지 않습니다."));
            assertFalse(output.contains("번호: 999"));
        }

        @Test
        @DisplayName("올바른 ID로 요청 시 게시글 내용이 정확하게 출력되는지 확인")
        void showsDetailWhenIdIsValid() {
            String output = runAppWithInput("write", "자바 공부", "자바 텍스트 게시판 만들기", "detail 1", "exit");

            assertContainsAll(output,
                    "번호: 1",
                    "제목: 자바 공부",
                    "내용: 자바 텍스트 게시판 만들기",
                    "등록일:",
                    "조회수: 1");
        }

        @Test
        @DisplayName("상세보기를 여러 번 요청하면 조회수가 증가하는지 확인")
        void increasesViewCountOnEachDetail() {
            String output = runAppWithInput(
                    "write", "자바 공부", "자바 텍스트 게시판 만들기",
                    "detail 1",
                    "detail 1",
                    "exit"
            );

            assertContainsAll(output, "조회수: 1", "조회수: 2");
        }
    }

    @Nested
    @DisplayName("게시글 수정(updateArticle) 테스트")
    class UpdateArticleTest {

        @Test
        @DisplayName("존재하지 않는 ID로 수정 요청 시 예외 상황 메시지가 출력되는지 확인")
        void showsErrorMessageWhenUpdateIdDoesNotExist() {
            String output = runAppWithInput("update 999", "exit");

            assertTrue(output.contains("해당 아이디는 존재하지 않습니다."));
            assertFalse(output.contains("=> 게시글이 수정되었습니다."));
        }

        @Test
        @DisplayName("제목과 내용을 수정할 때, 수정된 내용이 올바르게 반영되는지 확인")
        void updatesTitleAndContentCorrectly() {
            String output = runAppWithInput(
                    "write", "원래 제목", "원래 내용",
                    "update 1", "수정 제목", "수정 내용",
                    "detail 1",
                    "exit"
            );

            assertContainsAll(output,
                    "=> 게시글이 수정되었습니다.",
                    "제목: 수정 제목",
                    "내용: 수정 내용");
        }

        @Test
        @DisplayName("제목 또는 내용이 비어있을 때 수정이 불가능한지 확인")
        void cannotUpdateWhenTitleOrContentIsEmpty() {
            String emptyTitleOutput = runAppWithInput(
                    "write", "원래 제목", "원래 내용",
                    "update 1", "", "수정 내용",
                    "detail 1",
                    "exit"
            );

            assertContainsAll(emptyTitleOutput,
                    "제목/내용은 비어 있을 수 없습니다.",
                    "제목: 원래 제목",
                    "내용: 원래 내용");

            String emptyContentOutput = runAppWithInput(
                    "write", "원래 제목", "원래 내용",
                    "update 1", "수정 제목", "",
                    "detail 1",
                    "exit"
            );

            assertContainsAll(emptyContentOutput,
                    "제목/내용은 비어 있을 수 없습니다.",
                    "제목: 원래 제목",
                    "내용: 원래 내용");
        }
    }

    @Nested
    @DisplayName("게시글 삭제(deleteArticle) 테스트")
    class DeleteArticleTest {

        @Test
        @DisplayName("존재하지 않는 ID로 삭제 요청 시 예외 상황 메시지가 출력되는지 확인")
        void showsErrorMessageWhenDeleteIdDoesNotExist() {
            String output = runAppWithInput("delete 999", "exit");

            assertTrue(output.contains("해당 아이디는 존재하지 않습니다."));
            assertFalse(output.contains("=> 게시글이 삭제되었습니다."));
        }

        @Test
        @DisplayName("게시글이 삭제된 후 목록에서 해당 게시글이 없는지 확인")
        void deletedArticleDoesNotAppearInList() {
            String output = runWithTwoArticlesThen("delete 1", "list");

            assertContainsAll(output, "=> 게시글이 삭제되었습니다.", "2    | 두번째 제목");
            assertFalse(output.contains("1    | 첫번째 제목"));
        }
    }

    @Nested
    @DisplayName("게시글 검색(search) 테스트")
    class SearchArticleTest {

        @Test
        @DisplayName("검색어가 제목/내용에 포함된 게시글만 출력되는지 확인")
        void showsOnlyMatchedArticles() {
            String output = runAppWithInput(
                    "write", "자바 공부", "컬렉션 학습",
                    "write", "스프링 공부", "자바 백엔드",
                    "search 자바",
                    "exit"
            );

            assertContainsAll(output, "1    | 자바 공부", "2    | 스프링 공부");
        }

        @Test
        @DisplayName("search 결과에도 조회수가 함께 표시되는지 확인")
        void showsViewCountInSearchResult() {
            String output = runAppWithInput(
                    "write", "자바 공부", "컬렉션 학습",
                    "detail 1",
                    "search 자바",
                    "exit"
            );

            assertContainsAll(output, "번호 | 제목 | 등록일 | 조회수", "1    | 자바 공부", "| 1");
        }

        @Test
        @DisplayName("검색 결과가 없으면 안내 문구가 출력되는지 확인")
        void showsEmptyMessageWhenNoSearchResult() {
            String output = runWithTwoArticlesThen("search 파이썬");

            assertTrue(output.contains("(검색 결과 없음)"));
        }
    }



}

package com.ll;

import java.io.ByteArrayInputStream;
import java.io.ByteArrayOutputStream;
import java.io.InputStream;
import java.io.PrintStream;
import java.nio.charset.StandardCharsets;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;

import static org.assertj.core.api.Assertions.assertThat;

@DisplayName("App 테스트")
class AppTest {

    private App app;

    @BeforeEach
    void setUp() {
        app = new App();
    }

    // 콘솔 입력(lines)을 주입해 App을 실행하고 출력 문자열을 반환하는 테스트 헬퍼
    private String runAppWithInput(String... lines) {
        InputStream originalIn = System.in;
        PrintStream originalOut = System.out;
        ByteArrayOutputStream outputBuffer = new ByteArrayOutputStream();

        try {
            String input = String.join(System.lineSeparator(), lines) + System.lineSeparator();
            System.setIn(new ByteArrayInputStream(input.getBytes(StandardCharsets.UTF_8)));
            System.setOut(new PrintStream(outputBuffer, true, StandardCharsets.UTF_8));

            App consoleApp = new App();
            consoleApp.run();

            return outputBuffer.toString(StandardCharsets.UTF_8);
        } finally {
            System.setIn(originalIn);
            System.setOut(originalOut);
        }
    }

    // 중복 코드 리펙토링
    private String[] writeCommand(String title, String content) {
        return new String[]{"write", title, content};
    }

    private String runWithTwoArticlesThen(String... tailCommands) {
        String[] first = writeCommand("첫번째 제목", "첫번째 내용");
        String[] second = writeCommand("두번째 제목", "두번째 내용");
        String[] all = new String[first.length + second.length + tailCommands.length + 1];

        int idx = 0;
        for (String cmd : first) all[idx++] = cmd;
        for (String cmd : second) all[idx++] = cmd;
        for (String cmd : tailCommands) all[idx++] = cmd;
        all[idx] = "exit";

        return runAppWithInput(all);
    }

    // output에 expectedTexts가 모두 포함되는지 한 번에 검증하는 헬퍼
    private void assertContainsAll(String output, String... expectedTexts) {
        for (String expected : expectedTexts) {
            assertThat(output).contains(expected);
        }
    }

    // 마지막으로 출력된 list 표 블록(헤더부터)을 추출하는 헬퍼
    private String extractLastListBlock(String output) {
        String header = "번호 | 제목 | 등록일 | 조회수";
        int idx = output.lastIndexOf(header);
        if (idx < 0) return "";
        return output.substring(idx);
    }

    // --------------------------------------
    // 테스트 케이스
    // --------------------------------------
    @Nested
    @DisplayName("게시글 목록 출력(listArticles) 테스트")
    class ListArticlesTest {

        @Test
        @DisplayName("게시글이 없을 때 빈 목록이 출력되는지 확인")
        void showsEmptyMessageWhenNoArticles() {
            String output = runAppWithInput("list", "exit");

            assertThat(output).contains("번호 | 제목 | 등록일 | 조회수");
            assertThat(output).contains("(게시글 없음)");
        }

        @Test
        @DisplayName("여러 게시글이 등록되었을 때, 목록이 올바르게 출력되는지 확인")
        void showsAllArticlesInList() {
            String output = runWithTwoArticlesThen("list");

            assertContainsAll(output, "1    | 첫번째 제목", "2    | 두번째 제목");
        }

        @Test
        @DisplayName("최신 게시글이 목록의 상단에 위치하는지 확인")
        void latestArticleAppearsFirst() {
            String output = runWithTwoArticlesThen("list");

            int secondIndex = output.indexOf("2    | 두번째 제목");
            int firstIndex = output.indexOf("1    | 첫번째 제목");

            assertThat(secondIndex).isGreaterThanOrEqualTo(0);
            assertThat(firstIndex).isGreaterThanOrEqualTo(0);
            assertThat(secondIndex).isLessThan(firstIndex);
        }

        @Test
        @DisplayName("list에서 신규 게시글 조회수가 0으로 표시되는지 확인")
        void showsZeroViewCountInListForNewArticle() {
            String output = runAppWithInput(
                    "write", "조회수 초기 테스트", "내용",
                    "list",
                    "exit"
            );

            String listBlock = extractLastListBlock(output);
            assertContainsAll(listBlock, "번호 | 제목 | 등록일 | 조회수", "1    | 조회수 초기 테스트", "| 0");
        }

        @Test
        @DisplayName("detail 이후 list에서 조회수가 증가한 값으로 표시되는지 확인")
        void reflectsIncreasedViewCountInListAfterDetail() {
            String output = runAppWithInput(
                    "write", "조회수 반영 테스트", "내용",
                    "detail 1",
                    "list",
                    "exit"
            );

            String listBlock = extractLastListBlock(output);
            assertContainsAll(listBlock, "1    | 조회수 반영 테스트", "| 1");
        }

        @Test
        @DisplayName("여러 게시글 중 상세 조회한 게시글만 조회수가 증가하는지 확인")
        void increasesViewCountOnlyForViewedArticleInList() {
            String output = runAppWithInput(
                    "write", "첫번째 글", "내용1",
                    "write", "두번째 글", "내용2",
                    "detail 1",
                    "list",
                    "exit"
            );

            String listBlock = extractLastListBlock(output);
            assertContainsAll(listBlock, "2    | 두번째 글", "| 0", "1    | 첫번째 글", "| 1");
        }
    }

    @Nested
    @DisplayName("게시글 상세보기(showDetail) 테스트 케이스")
    class ShowDetailTest {

        @Test
        @DisplayName("존재하지 않는 ID로 상세보기를 요청할 때 예외가 발생하는지 확인")
        void showsErrorMessageWhenIdDoesNotExist() {
            String output = runAppWithInput("detail 999", "exit");

            assertThat(output).contains("해당 아이디는 존재하지 않습니다.");
            assertThat(output).doesNotContain("번호: 999");
        }

        @Test
        @DisplayName("올바른 ID로 요청 시 게시글 내용이 정확하게 출력되는지 확인")
        void showsDetailWhenIdIsValid() {
            String output = runAppWithInput("write", "자바 공부", "자바 텍스트 게시판 만들기", "detail 1", "exit");

            assertContainsAll(output,
                    "번호: 1",
                    "제목: 자바 공부",
                    "내용: 자바 텍스트 게시판 만들기",
                    "등록일:",
                    "조회수: 1");
        }

        @Test
        @DisplayName("상세보기를 여러 번 요청하면 조회수가 증가하는지 확인")
        void increasesViewCountOnEachDetail() {
            String output = runAppWithInput(
                    "write", "자바 공부", "자바 텍스트 게시판 만들기",
                    "detail 1",
                    "detail 1",
                    "exit"
            );

            assertContainsAll(output, "조회수: 1", "조회수: 2");
        }
    }

    @Nested
    @DisplayName("게시글 수정(updateArticle) 테스트")
    class UpdateArticleTest {

        @Test
        @DisplayName("존재하지 않는 ID로 수정 요청 시 예외 상황 메시지가 출력되는지 확인")
        void showsErrorMessageWhenUpdateIdDoesNotExist() {
            String output = runAppWithInput("update 999", "exit");

            assertThat(output).contains("해당 아이디는 존재하지 않습니다.");
            assertThat(output).doesNotContain("=> 게시글이 수정되었습니다.");
        }

        @Test
        @DisplayName("제목과 내용을 수정할 때, 수정된 내용이 올바르게 반영되는지 확인")
        void updatesTitleAndContentCorrectly() {
            String output = runAppWithInput(
                    "write", "원래 제목", "원래 내용",
                    "update 1", "수정 제목", "수정 내용",
                    "detail 1",
                    "exit"
            );

            assertContainsAll(output,
                    "=> 게시글이 수정되었습니다.",
                    "제목: 수정 제목",
                    "내용: 수정 내용");
        }

        @Test
        @DisplayName("제목 또는 내용이 비어있을 때 수정이 불가능한지 확인")
        void cannotUpdateWhenTitleOrContentIsEmpty() {
            String emptyTitleOutput = runAppWithInput(
                    "write", "원래 제목", "원래 내용",
                    "update 1", "", "수정 내용",
                    "detail 1",
                    "exit"
            );

            assertContainsAll(emptyTitleOutput,
                    "제목/내용은 비어 있을 수 없습니다.",
                    "제목: 원래 제목",
                    "내용: 원래 내용");

            String emptyContentOutput = runAppWithInput(
                    "write", "원래 제목", "원래 내용",
                    "update 1", "수정 제목", "",
                    "detail 1",
                    "exit"
            );

            assertContainsAll(emptyContentOutput,
                    "제목/내용은 비어 있을 수 없습니다.",
                    "제목: 원래 제목",
                    "내용: 원래 내용");
        }
    }

    @Nested
    @DisplayName("게시글 삭제(deleteArticle) 테스트")
    class DeleteArticleTest {

        @Test
        @DisplayName("존재하지 않는 ID로 삭제 요청 시 예외 상황 메시지가 출력되는지 확인")
        void showsErrorMessageWhenDeleteIdDoesNotExist() {
            String output = runAppWithInput("delete 999", "exit");

            assertThat(output).contains("해당 아이디는 존재하지 않습니다.");
            assertThat(output).doesNotContain("=> 게시글이 삭제되었습니다.");
        }

        @Test
        @DisplayName("게시글이 삭제된 후 목록에서 해당 게시글이 없는지 확인")
        void deletedArticleDoesNotAppearInList() {
            String output = runWithTwoArticlesThen("delete 1", "list");

            assertContainsAll(output, "=> 게시글이 삭제되었습니다.", "2    | 두번째 제목");
            assertThat(output).doesNotContain("1    | 첫번째 제목");
        }
    }

    @Nested
    @DisplayName("게시글 검색(search) 테스트")
    class SearchArticleTest {

        @Test
        @DisplayName("검색어가 제목/내용에 포함된 게시글만 출력되는지 확인")
        void showsOnlyMatchedArticles() {
            String output = runAppWithInput(
                    "write", "자바 공부", "컬렉션 학습",
                    "write", "스프링 공부", "자바 백엔드",
                    "search 자바",
                    "exit"
            );

            assertContainsAll(output, "1    | 자바 공부", "2    | 스프링 공부");
        }

        @Test
        @DisplayName("search 결과에도 조회수가 함께 표시되는지 확인")
        void showsViewCountInSearchResult() {
            String output = runAppWithInput(
                    "write", "자바 공부", "컬렉션 학습",
                    "detail 1",
                    "search 자바",
                    "exit"
            );

            assertContainsAll(output, "번호 | 제목 | 등록일 | 조회수", "1    | 자바 공부", "| 1");
        }

        @Test
        @DisplayName("검색 결과가 없으면 안내 문구가 출력되는지 확인")
        void showsEmptyMessageWhenNoSearchResult() {
            String output = runWithTwoArticlesThen("search 파이썬");

            assertThat(output).contains("(검색 결과 없음)");
        }
    }



}

package com.ll;

import java.util.List;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertNotNull;
import static org.junit.jupiter.api.Assertions.assertNull;
import static org.junit.jupiter.api.Assertions.assertThrows;
import static org.junit.jupiter.api.Assertions.assertTrue;

@DisplayName("ArticleService 테스트")
class ArticleServiceTest {

    private ArticleService service;

    @BeforeEach
    void setUp() {
        service = new ArticleService();
    }

    @Nested
    @DisplayName("write() 테스트")
    class WriteTest {

        @Test
        @DisplayName("제목과 내용을 입력하면 게시글이 생성되고 id가 1부터 증가하는지 확인")
        void createsArticleWithIncrementingId() {
            Article first = service.write("제목1", "내용1");
            Article second = service.write("제목2", "내용2");

            assertEquals(1, first.getId());
            assertEquals(2, second.getId());
        }

        @Test
        @DisplayName("제목이 빈 문자열이면 예외가 발생하는지 확인")
        void throwsWhenTitleIsEmpty() {
            assertThrows(IllegalArgumentException.class, () -> service.write("", "내용"));
        }

        @Test
        @DisplayName("내용이 빈 문자열이면 예외가 발생하는지 확인")
        void throwsWhenContentIsEmpty() {
            assertThrows(IllegalArgumentException.class, () -> service.write("제목", ""));
        }
    }

    @Nested
    @DisplayName("findById() 테스트")
    class FindByIdTest {

        @Test
        @DisplayName("존재하는 id로 조회하면 해당 게시글을 반환하는지 확인")
        void returnsArticleWhenIdExists() {
            service.write("자바 공부", "내용");

            Article found = service.findById(1);

            assertNotNull(found);
            assertEquals("자바 공부", found.getTitle());
        }

        @Test
        @DisplayName("존재하지 않는 id로 조회하면 null을 반환하는지 확인")
        void returnsNullWhenIdDoesNotExist() {
            assertNull(service.findById(999));
        }
    }

    @Nested
    @DisplayName("delete() 테스트")
    class DeleteTest {

        @Test
        @DisplayName("게시글 삭제 후 findAll()에서 제거되는지 확인")
        void removesArticleFromList() {
            Article post = service.write("삭제할 글", "내용");
            boolean deleted = service.deleteById(post.getId());

            assertTrue(deleted);
            assertTrue(service.findAll().isEmpty());
        }

        @Test
        @DisplayName("존재하지 않는 id 삭제 시 false를 반환하는지 확인")
        void returnsFalseWhenDeleteIdDoesNotExist() {
            boolean deleted = service.deleteById(999);

            assertFalse(deleted);
        }
    }

    @Nested
    @DisplayName("modify() 테스트")
    class ModifyTest {

        @Test
        @DisplayName("수정 후 제목과 내용이 변경되는지 확인")
        void updatesTitleAndContent() {
            Article post = service.write("원래 제목", "원래 내용");
            boolean modified = service.modifyById(post.getId(), "수정 제목", "수정 내용");

            assertTrue(modified);
            assertEquals("수정 제목", post.getTitle());
            assertEquals("수정 내용", post.getContent());
        }

        @Test
        @DisplayName("존재하지 않는 id 수정 시 false를 반환하는지 확인")
        void returnsFalseWhenModifyIdDoesNotExist() {
            boolean modified = service.modifyById(999, "수정 제목", "수정 내용");

            assertFalse(modified);
        }
    }

    @Test
    @DisplayName("findAll()로 받은 리스트는 수정할 수 없는지 확인")
    void findAllReturnsUnmodifiableList() {
        service.write("제목", "내용");

        List<Article> posts = service.findAll();

        assertThrows(UnsupportedOperationException.class,
                () -> posts.add(new Article(999, "외부 추가", "내용")));
    }

    @Nested
    @DisplayName("search() 테스트")
    class SearchTest {

        @Test
        @DisplayName("키워드가 제목에 포함된 게시글만 반환하는지 확인")
        void returnsArticlesMatchingByTitle() {
            service.write("자바 공부", "컬렉션 학습");
            service.write("스프링 공부", "DI 학습");

            List<Article> result = service.search("자바");

            assertEquals(1, result.size());
            assertEquals("자바 공부", result.get(0).getTitle());
        }

        @Test
        @DisplayName("키워드가 내용에 포함된 게시글도 반환하는지 확인")
        void returnsArticlesMatchingByContent() {
            service.write("공부 일지", "자바 백엔드 개발");
            service.write("취미 기록", "독서");

            List<Article> result = service.search("자바");

            assertEquals(1, result.size());
            assertEquals("공부 일지", result.get(0).getTitle());
        }

        @Test
        @DisplayName("키워드가 없으면 빈 리스트를 반환하는지 확인")
        void returnsEmptyListWhenNoMatch() {
            service.write("자바 공부", "내용");

            List<Article> result = service.search("파이썬");

            assertTrue(result.isEmpty());
        }
    }
}

